html: <!-- Solution HTML for Accessible Slider -->
<div class='h-screen flex justify-center items-center'>
  <div class='w-2/3 max-w-md mx-auto'>
    <input type='range' id='slider' class='w-full h-full p-2' value='50' aria-label='Slider' aria-valuenow='50' aria-valuemin='0' aria-valuemax='100' aria-describedby='value-desc'>
    <p id='value' class='text-lg font-bold mt-4'></p>
    <p id='value-desc' class='text-sm mt-2' aria-live='assertive'>Slider value: 50</p>
  </div>
</div>

<script src='script.js'></script>
css: /* Solution CSS for Accessible Slider */
.slider {
  @apply w-full h-full p-2;
  /* Add your styles here */
}

/* styles for accessibility */
#value-desc {
  @apply text-sm mt-2;
}
js: // Solution JavaScript for Accessible Slider
const slider = document.getElementById('slider');
const valueElement = document.getElementById('value');
const valueDesc = document.getElementById('value-desc');

slider.addEventListener('input', () => {
  const value = slider.value;
  valueElement.textContent = value;
  valueDesc.textContent = `Slider value: ${value}`;
  document.getElementById('slider').setAttribute('aria-valuenow', value);
});

window.addEventListener('keydown', (e) => {
  if (e.key === 'ArrowUp' && slider.value < 100) {
    slider.value = parseInt(slider.value) + 1;
  } else if (e.key === 'ArrowDown' && slider.value > 0) {
    slider.value = parseInt(slider.value) - 1;
  }
  const value = slider.value;
  valueElement.textContent = value;
  valueDesc.textContent = `Slider value: ${value}`;
  document.getElementById('slider').setAttribute('aria-valuenow', value);
});
